INSERT INTO `mdl_course` (`id`, `category`, `sortorder`, `fullname`, `shortname`, `idnumber`, `summary`, `summaryformat`, `format`, `showgrades`, `newsitems`, `startdate`, `enddate`, `relativedatesmode`, `marker`, `maxbytes`, `legacyfiles`, `showreports`, `visible`, `visibleold`, `downloadcontent`, `groupmode`, `groupmodeforce`, `defaultgroupingid`, `lang`, `calendartype`, `theme`, `timecreated`, `timemodified`, `requested`, `enablecompletion`, `completionnotify`, `cacherev`, `originalcourseid`, `showactivitydates`, `showcompletionconditions`, `pdfexportfont`) VALUES
(1, 0, 1, 'AI & Cybersecurity Defense Academy', 'AI&CDA', '', '<p>Welcome to the <strong data-path-to-node=\"8,0\" data-index-in-node=\"15\">AI &amp; Cybersecurity Defense Academy</strong> e-learning portal. Dive into specialized training where artificial intelligence meets elite cyber defense. Access your learning materials, collaborate with peers, and build the practical skills required to secure tomorrow\'s digital landscape.</p>', 0, 'site', 1, 3, 0, 0, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1778137010, 1779376203, 0, 0, 0, 1779586448, NULL, 0, NULL, NULL),
(3, 5, 10004, 'Introduction to Machine Learning for Security', 'IMLS-1', '', '<p>Learn the core concepts of supervised and unsupervised learning, and how to apply basic algorithms to identify patterns in network traffic.</p>', 1, 'topics', 1, 5, 1779404400, 1810940400, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779376951, 1779376951, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(4, 5, 10003, 'Neural Networks & Deep Learning Basics', 'NNDLP-1', '', '<p>Dive into the architecture of deep learning. Understand how artificial neural networks process complex data to mimic human decision-making.</p>', 1, 'topics', 1, 5, 1779404400, 1810940400, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779376989, 1779376989, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(5, 5, 10002, 'Data Science and Analytics for Engineers', 'DSAE', '', '<p>Master the tools needed to clean, visualize, and analyze massive datasets, turning raw digital noise into actionable security insights.</p>', 1, 'topics', 1, 5, 1779404400, 1810940400, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779377013, 1779377013, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(6, 5, 10001, 'Natural Language Processing in Tech', 'NLPT', '', '<p>Explore how AI understands human language, a critical skill for analyzing phishing emails, chat logs, and malicious code documentation.</p>', 1, 'topics', 1, 5, 1779404400, 1810940400, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779377035, 1779377035, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(7, 6, 20004, 'AI-Driven Threat Hunting', 'AITH', '', '<p>Move from reactive to proactive defense. Learn to use AI models to sniff out hidden attackers and anomalies lurking deep within your network.</p>', 1, 'topics', 1, 5, 1779404400, 1810940400, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779377060, 1779377060, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(8, 6, 20003, 'Next-Gen Network Security & Firewalls', 'NNSF', '', '<p>Master the deployment and management of intelligent firewalls and intrusion prevention systems that adapt to threats in real time.</p>', 1, 'topics', 1, 5, 1779404400, 1810940400, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779377083, 1779377083, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(9, 6, 20002, 'Ethical Hacking & Vulnerability Assessment', 'EHVS', '', '<p>Think like a hacker to protect the castle. Learn modern penetration testing techniques to find and patch security flaws before the bad guys do.</p>', 1, 'topics', 1, 5, 1779404400, 1810940400, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779377101, 1779377101, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(10, 6, 20001, 'Cloud Security Architecture', 'CSA', '', '<p>Secure modern cloud environments (AWS, Azure, GCP) by implementing robust identity management, encryption, and automated defense protocols.</p>', 1, 'topics', 1, 5, 1779404400, 1810940400, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779377126, 1779377126, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(11, 7, 30004, 'Computer & Memory Forensics', 'CMF', '', '<p>Learn the art of volatile memory (RAM) analysis and hard drive imaging to extract volatile data and catch malware in the act.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779540865, 1779540865, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(12, 7, 30003, 'Network Forensics & Traffic Analysis', 'NFTA', '', '<p>Intercept, reconstruct, and analyze network packets to trace the exact path an attacker took during a security breach.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779540889, 1779540889, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(13, 7, 30002, 'AI Tools for Automated Incident Response', 'ATAIR', '', '<p>Speed up your investigation. Learn how to leverage AI to automate log analysis and instantly isolate compromised systems during an attack.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779540915, 1779540915, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(14, 7, 30001, 'Mobile & IoT Device Investigations', 'MIOTDI', '', '<p>Step into the world of smart devices. Discover specialized techniques for recovering data from smartphones, wearables, and IoT infrastructure.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779540944, 1779540944, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(15, 8, 40004, 'Cybersecurity Leadership & Risk Management', 'CLRM', '', '<p>Learn to translate technical risks into business impact, manage security budgets, and lead high-performing technical teams.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779540971, 1779540971, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(16, 8, 40003, 'Crisis Communication & Incident Governance', 'CCIG', '', '<p>Master the chaos of a breach. Learn how to legally, ethically, and effectively communicate with stakeholders, PR, and law enforcement during a crisis.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779540996, 1779540996, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(17, 8, 40002, 'AI Ethics, Privacy & Compliance', 'AEPC', '', '<p>Navigate the complex legal landscape of AI. Understand GDPR, AI regulations, and bias mitigation to ensure your defenses remain ethical and lawful.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779541016, 1779541016, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(18, 8, 40001, 'Strategic Technical Writing & Reporting', 'STWR', '', '<p>Bridge the gap between the server room and the boardroom. Learn to write flawless incident reports and executive summaries that C-level executives understand.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779541037, 1779541037, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(19, 9, 50004, 'Certified AI Security Specialist Bootcamp', 'CAISS', '', '<p>An intensive prep course focused on securing AI pipelines and using machine learning for defensive operations.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779541065, 1779541065, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(20, 9, 50003, 'CompTIA Security+ Accelerated', 'CTIASA', '', '<p>The ultimate fast-track course to master the baseline skills required to land your first core cybersecurity role and ace the Security+ exam.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779541098, 1779541098, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(21, 9, 50002, 'Certified Information Systems Security Professional Cram', 'CISSP', '', '<p>A high-pressure, comprehensive review of the 8 CISSP domains, designed for senior practitioners aiming for elite industry validation.</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779541124, 1779541124, 0, 1, 0, 1779586448, NULL, 1, 1, NULL),
(22, 9, 50001, 'Certified Ethical Hacker Exam Prep', 'CEH', '', '<p>Sharpen your skills and review the exact methodologies, tools, and</p>', 1, 'topics', 1, 5, 1779577200, 1811113200, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1779541159, 1779541159, 0, 1, 0, 1779586448, NULL, 1, 1, NULL);
INSERT INTO `mdl_course_categories` (`id`, `name`, `idnumber`, `description`, `descriptionformat`, `parent`, `sortorder`, `coursecount`, `visible`, `visibleold`, `timemodified`, `depth`, `path`, `theme`) VALUES
(5, 'Artificial Intelligence Fundamentals', '', '<p>Build the groundwork for modern defense. This category covers the essentials of machine learning, neural networks, and data analytics, teaching you how AI systems think, learn, and adapt to complex data environments.</p>', 1, 0, 10000, 4, 1, 1, 1779376648, 1, '/5', NULL),
(6, 'Cybersecurity Defense', '', '<p>Master the art of proactive protection. Explore advanced methodologies, threat hunting, and network security strategies designed to leverage AI capabilities and shield critical digital infrastructure from sophisticated cyberattacks.</p>', 1, 0, 20000, 4, 1, 1, 1779376676, 1, '/6', NULL),
(7, 'Digital Forensics', '', '<p>Learn to decode the aftermath of a breach. This section focuses on incident response, data recovery, and evidence analysis, utilizing cutting-edge tools to investigate cybercrimes and understand attacker behavior.</p>', 1, 0, 30000, 4, 1, 1, 1779376702, 1, '/7', NULL),
(8, 'Professional Skills', '', '<p>Bridge the gap between technical expertise and leadership. Develop essential career competencies, including cybersecurity ethics, risk management, crisis communication, and strategic decision-making for the modern tech landscape</p>', 1, 0, 40000, 4, 1, 1, 1779376725, 1, '/8', NULL),
(9, 'Intensive Certifications', '', '<p>Fast-track your career validation. Access specialized, high-impact bootcamps and preparatory courses engineered to help you ace industry-recognized AI and cybersecurity examinations with confidence.</p>', 1, 0, 50000, 4, 1, 1, 1779376752, 1, '/9', NULL);
